-- RAG knowledge base for ASCS Opportunity Assistant.
-- Cleaned from Historical_Opportunities.xlsx, PL_Industry_Challenge.xlsx,
-- Service_description.pptx. Run AFTER setup.sql + fix_login.sql.
-- Idempotent: drops and recreates the three knowledge tables.

drop table if exists public.rag_chunks cascade;
drop table if exists public.pricing_matrix cascade;
drop table if exists public.historical_opportunities cascade;

create table public.historical_opportunities (
  opportunity_id text primary key,
  company_name text not null,
  industry text not null,
  year int not null,
  source text,
  incumbent_carrier text,
  daily_volume_total int,
  geo_fit_pct numeric,
  daily_volume_serviceable int,
  avg_weight_kg numeric,
  oversized_pct numeric,
  requires_intl boolean,
  intl_volume_share numeric,
  requires_pudo boolean,
  requires_b2b boolean,
  weekend_need boolean,
  annual_revenue_potential_eur numeric,
  main_pain_point text,
  pain_severity int,
  price_vs_incumbent_pct numeric,
  competitive_intensity int,
  sales_cycle_touches int,
  decision_time_days int,
  contract_length_months int,
  outcome text check (outcome in ('Won','Lost')),
  lost_reason text,
  final_margin_pct numeric
);

create table public.pricing_matrix (
  id bigserial primary key,
  cost_component text not null check (cost_component in ('first_mile','middle_mile','home_delivery','other_fixed')),
  volume_band text not null,
  volume_min int not null,
  volume_max int,
  weight_band text not null,
  weight_max_kg numeric not null,
  cost_eur numeric not null,
  unique (cost_component, volume_band, weight_band)
);

create table public.rag_chunks (
  id bigserial primary key,
  source text not null,
  title text not null,
  content text not null,
  metadata jsonb not null default '{}',
  fts tsvector generated always as (to_tsvector('english', coalesce(title,'') || ' ' || content)) stored
);
create index rag_chunks_fts_idx on public.rag_chunks using gin (fts);
create index rag_chunks_source_idx on public.rag_chunks (source);

-- Retrieval function for the model (full-text, ranked).
-- Upgrade path: add a vector column + pgvector for semantic search.
create or replace function public.search_knowledge(query text, top_k int default 8)
returns table (id bigint, source text, title text, content text, metadata jsonb, rank real)
language sql stable as $$
  select c.id, c.source, c.title, c.content, c.metadata,
         ts_rank(c.fts, websearch_to_tsquery('english', query)) as rank
  from public.rag_chunks c
  where c.fts @@ websearch_to_tsquery('english', query)
  order by rank desc
  limit top_k
$$;

-- Internal data (margins, costs): employees and admins only.
alter table public.historical_opportunities enable row level security;
alter table public.pricing_matrix enable row level security;
alter table public.rag_chunks enable row level security;

create policy "employees read opportunities knowledge" on public.historical_opportunities
  for select using (public.current_user_role() in ('Employee','Admin'));
create policy "employees read pricing" on public.pricing_matrix
  for select using (public.current_user_role() in ('Employee','Admin'));
create policy "employees read chunks" on public.rag_chunks
  for select using (public.current_user_role() in ('Employee','Admin'));
















